```javascript
function renderSoundline(numbers) {
  const soundline = document.querySelector('.soundline');
  soundline.innerHTML = '';
  numbers.forEach((num, i) => {
    const el = document.createElement('div');
    el.className = 'soundline-number';
    el.textContent = num;
