```javascript
import createFractionEditor from '../../libs/app-common/fraction-editor.js';
import { addRepeatPress } from '../../libs/app-common/spinner-repeat.js';

function buildMiddleLayout() {
  const middle = document.querySelector('.middle');
  middle.classList.add('myapp-middle');
  middle.innerHTML = '';

  // Opcional: info pills a la dreta (Suma iT, iT Disponibles)
  const infoGroup = document.createElement('div');
  infoGroup.className = 'itfr-info-group';

  const sumBox = document.createElement('div');
  sumBox.className = 'bpm-inline visible param sum-it';
  sumBox.innerHTML = `
    <span class="abbr">Suma iT</span>
    <div class="circle"><input id="sumItDisplay" type="text" value="0" readonly /></div>
  `;

  const dispBox = document.createElement('div');
  dispBox.className = 'bpm-inline visible param it-disponibles';
  dispBox.innerHTML = `
    <span class="abbr">iT Disponibles</span>
    <div class="circle"><input id="itDisponiblesDisplay" type="text" value="0" readonly /></div>
  `;

  infoGroup.appendChild(sumBox);
  infoGroup.appendChild(dispBox);
  middle.appendChild(infoGroup);

  // Slot de la fracció (esquerra)
  const fractionSlot = document.createElement('div');
  fractionSlot.className = 'itfr-fraction-slot';
  middle.appendChild(fractionSlot);

  return { fractionSlot, sumDisplay: sumBox.querySelector('input'), lengthDisplay: dispBox.querySelector('input') };
}

const { fractionSlot, sumDisplay, lengthDisplay } = buildMiddleLayout();

const controller = createFractionEditor({
  mode: 'block',
  host: fractionSlot,
  defaults: { numerator: 1, denominator: 2 },
  startEmpty: false,
  maxDenominator: 8,
  enableGhost: false,        // simple → kill ghost
  storage: {},
  addRepeatPress,
  onChange: ({ cause }) => {
    if (cause !== 'init') handleFractionChange();
  }
});
controller.setSimpleMode();
```

La fracció queda a l'esquerra (alineada amb endcap via CSS `left: calc(-W)`), els pills a la dreta (alineats amb endcap dret via `right: calc(-W)` o `right: 0` segons app standalone vs plano-2D).

```javascript
import { createMelodicAudioInitializer } from '../../libs/app-common/audio-init.js';
import { bindSharedSoundEvents } from '../../libs/app-common/audio.js';

let audio = null;

const _baseInitAudio = createMelodicAudioInitializer({
  defaultInstrument: 'piano'
});

bindSharedSoundEvents({
  getAudio: () => audio,
  mapping: { baseSound: 'setBase', cycleSound: 'setCycle' }
});

async function initAudio() {
  if (!audio) {
    audio = await _baseInitAudio();

    // CRITICAL: guard every call with `audio &&` — `audio` can be null if
    // Tone.js fails to load or melodic-audio.js dynamic import fails silently.
    // `typeof X === 'function'` does NOT protect against null.X access.
    const savedMute = loadOpt('mute');
    if (audio && savedMute === '1' && typeof audio.setMute === 'function') {
      audio.setMute(true);
    }

    if (audio && baseSoundSelect?.dataset?.value && typeof audio.setBase === 'function') {
      await audio.setBase(baseSoundSelect.dataset.value);
    }
    if (audio && cycleSoundSelect?.dataset?.value && typeof audio.setCycle === 'function') {
      await audio.setCycle(cycleSoundSelect.dataset.value);
    }

    if (audio && typeof window !== 'undefined') {
      window.__labAudio = audio;
      window.NuzicAudioEngine = audio;
    }
  }
  return audio;
}

if (typeof window !== 'undefined') {
  window.__labInitAudio = initAudio;
  document.addEventListener('click', () => initAudio(), { once: true });
  document.addEventListener('touchstart', () => initAudio(), { once: true });
}
```

The `audio &&` guards prevent `Cannot read properties of null (reading 'setBase')` errors that occur when the audio system fails silently.

En plano-2D els endcaps són diferents que en standalone:
- **Esquerre**: aprofitem la cantonada inferior-esquerra del grid (cel·la col 1 row 2 del `.plano-container`) amb un gradient diagonal rosa→groc.
- **Dret**: `::after` overlay groc sobre `.plano-timeline-container`.

```css
body.myapp {
  --myapp-endcap-w: clamp(1.875rem, 5.25vw, 5rem);
  --myapp-endcap-h: clamp(3.8rem, 4vw, 4.75rem);
}

/* Cantonada inferior-esquerra: triangle rosa/groc */
body[data-visual="nuzic"].myapp .plano-container {
  gap: 0 !important;
  position: relative;
}

body[data-visual="nuzic"].myapp .plano-container::before {
  background: linear-gradient(
    to bottom right,
    var(--nuzic-pink) 0%,
    var(--nuzic-pink) 49.5%,
    var(--nuzic-yellow) 50.5%,
    var(--nuzic-yellow) 100%
  ) !important;
  margin-top: calc(-1 * var(--plano-cell-height, 32px) / 2) !important;
}

/* Endcap dret: rectangle groc sobre timeline-container */
body[data-visual="nuzic"].myapp .plano-timeline-container {
  position: relative;
  height: var(--myapp-endcap-h) !important;
  min-height: var(--myapp-endcap-h) !important;
  overflow-y: visible !important;
  margin-top: calc(-1 * var(--plano-cell-height, 32px) / 2) !important;
  background: linear-gradient(
    to bottom,
    var(--nuzic-yellow-light) 0,
    var(--nuzic-yellow-light) 70%,
    var(--nuzic-yellow) 70%,
    var(--nuzic-yellow) 93%,
    var(--nuzic-yellow-light) 93%,
    var(--nuzic-yellow-light) 100%
  ) !important;
}

body[data-visual="nuzic"].myapp .plano-timeline-container::after {
  content: '';
  display: block;
  position: absolute;
  top: 0;
  right: 0;
  width: var(--myapp-endcap-w);
  height: 100%;
  background: var(--nuzic-yellow);
  z-index: 5;
  pointer-events: none;
}

/* Padding W a la dreta perquè les cel·les no es solapin amb l'endcap dret */
body[data-visual="nuzic"].myapp .plano-matrix-container,
body[data-visual="nuzic"].myapp .plano-timeline-container {
  padding-right: var(--myapp-endcap-w) !important;
  box-sizing: border-box;
}
```

No cal `::before` separat per a l'endcap esquerre — el triangle del `.plano-container::before` ja juga aquest rol.

Por defecto `nuzic-theme.css` aplica un `radial-gradient` dot a TODAS las `.plano-cell`. Para limitarlo a las celdas de pulso entero (clase `.pulse-boundary` añadida por JS):

```css
/* Desactivar dot en todas las celdas */
body[data-visual="nuzic"].myapp .plano-cell {
  background-image: none !important;
}

/* Dot solo en .pulse-boundary (col donde colIdx*n % d === 0) */
body[data-visual="nuzic"].myapp .plano-cell.pulse-boundary::before {
  content: '';
  position: absolute;
  /* Esquina bottom-left. Tamaño en clamp para escalar con viewport. */
  left: 0;
  bottom: 0;
  width: clamp(1.5px, 0.2vw, 3px);
  height: clamp(1.5px, 0.2vw, 3px);
  background: var(--nuzic-dark);
  border-radius: 50%;
  transform: translate(-50%, 50%);  /* círculo COMPLETO en la esquina */
  pointer-events: none;
  z-index: 11;     /* SOBRE las note-bars (z-index: 10) */
}

/* Sin border-left ni border-right — la rejilla vertical viene de los dots,
   no de líneas. */
.plano-cell {
  border-left: none !important;
}
.plano-cell.pulse-boundary {
  border-left: none !important;
}
```

JS marca las celdas pulse-boundary:

```javascript
// En renderGrid, después de updateMatrix:
const cells = gridElements.matrixContainer.querySelectorAll('.plano-cell');
cells.forEach(cell => {
  const colIndex = parseInt(cell.dataset.colIndex, 10);
  // Para simple (n=1): colIndex % d === 0
  // Para complex (n>1): (colIndex * n) % d === 0
  if ((colIndex * n) % d === 0) cell.classList.add('pulse-boundary');
});
```

El `transform: translate(-50%, 50%)` proyecta el círculo medio dentro / medio fuera de la celda, formando un círculo COMPLETO en la división. Sin esto el círculo se vería como un cuarto de cercle con dos líneas a 90°.

```css
/* Plano-2D: el .middle es full-width del viewport. position: relative
   anchorea las info-pills absolute. min-height para que las pills no se
   solapen con la fracción cuando son más altas que la fracción base. */
body[data-visual="nuzic"] .middle.myapp-middle {
  display: block !important;
  position: relative;
  width: 100%;
  margin: 0;
  padding: 1rem 0;
  box-sizing: border-box;
  min-height: calc(var(--myapp-endcap-w) * 2 + 0.4rem);
}

.itfr-fraction-slot {
  display: inline-block;
  vertical-align: top;
  margin-left: 0;
}

.itfr-info-group {
  position: absolute;
  top: 0;
  /* Plano-2D: right: 0 (NO calc(-W), las pills se quedan dentro del viewport).
     Standalone: right: calc(0 - W) (proyectadas fuera de .middle). */
  right: 0;
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
  align-items: flex-end;
}
```

En plano-2D el viewport es full-width y las pills quedan alineadas al borde derecho del viewport (igual que el endcap derecho de la timeline).

```css
/* Standalone: .middle té margins -W a banda i banda perquè coincideixi
   amb el .timeline-wrapper (que també té margins -W). La fracció queda
   alineada amb endcap esquerre via `left: -W`, les pills amb endcap dret
   via `right: calc(-W)`. */
body[data-visual="nuzic"] .middle.myapp-middle {
  display: block !important;
  position: relative;
  width: auto;
  margin: 0 var(--myapp-endcap-w) 5px var(--myapp-endcap-w);
  box-sizing: border-box;
  padding: 0;
  min-height: calc(var(--myapp-endcap-w) * 2 + 0.4rem);
}

.itfr-fraction-slot {
  display: inline-block;
  vertical-align: top;
}

.itfr-info-group {
  position: absolute;
  top: 0;
  /* Projectat fora del .middle a la dreta perquè les caixes quedin
     verticalment sobre l'endcap dret de la timeline (que també projecta
     `+W` respecte la timeline). */
  right: calc(0px - var(--myapp-endcap-w));
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
  align-items: flex-end;
}
```

Els margins `var(--myapp-endcap-w)` a `.middle` són els mateixos que als wrappers de timeline, garantint alineament vertical entre fracció, info pills, endcaps esquerre i endcap dret.

