```javascript
import { calculateVariableLg as _calcLg } from '../../libs/plano-fraccion/fraction-math.js';
import { gcd } from '../../libs/app-common/number-utils.js';

const BASE_LG = 12;
const MIN_NUMERATOR = 2;
const MAX_NUMERATOR = 6;
const MIN_DENOMINATOR = 2;
const MAX_DENOMINATOR = 8;

let currentNumerator = 2;
let currentDenominator = 3;
let currentLg = BASE_LG;

const controller = createFractionEditor({
  mode: 'block',
  host: fractionSlot,
  defaults: { numerator: currentNumerator, denominator: currentDenominator },
  autoReduce: true,            // animates n/d reduction when gcd > 1
  minNumerator: MIN_NUMERATOR,
  minDenominator: MIN_DENOMINATOR,
  maxNumerator: MAX_NUMERATOR,
  maxDenominator: MAX_DENOMINATOR,
  // NO enableGhost: false — ghost is needed for reduction preview
  addRepeatPress,
  onChange: handleFractionChange
});
controller.setComplexMode();

function handleFractionChange() {
  const f = controller.getFraction();
  if (!Number.isFinite(f.numerator) || !Number.isFinite(f.denominator)) return;
  currentNumerator = f.numerator;
  currentDenominator = f.denominator;
  currentLg = _calcLg(currentNumerator, BASE_LG);
  renderTimeline();
}

// Random with gcd(n,d) === 1 (matches autoReduce: true)
function randomizeFraction() {
  let newN, newD;
  do {
    newN = Math.floor(Math.random() * (MAX_NUMERATOR - MIN_NUMERATOR + 1)) + MIN_NUMERATOR;
    newD = Math.floor(Math.random() * (MAX_DENOMINATOR - MIN_DENOMINATOR + 1)) + MIN_DENOMINATOR;
  } while (gcd(newN, newD) !== 1);
  controller.setFraction(newN, newD);
}
```

Complex requires three math adaptations in timeline rendering:
- `(colIdx * n) % d === 0` to detect integer pulses.
- `(startSubdiv * n) / d` to convert note positions.
- `renderGhostPulseLines` for integer pulses that don't fall on cells.

