main.js — fracción complex:

```javascript
import { renderGhostPulseLines } from '../../libs/plano-fraccion/ghost-pulse.js';
import { calculateVariableLg as _calcLg } from '../../libs/plano-fraccion/fraction-math.js';
import { gcd } from '../../libs/app-common/number-utils.js';

const BASE_LG = 12;
let currentNumerator = 2;
let currentDenominator = 3;
let currentLg = _calcLg(currentNumerator, BASE_LG);

const controller = createFractionEditor({
  mode: 'block',
  host: fractionSlot,
  defaults: { numerator: 2, denominator: 3 },
  autoReduce: true,
  minNumerator: 2,
  maxNumerator: 6,
  minDenominator: 2,
  maxDenominator: 8,
  addRepeatPress
});
controller.setComplexMode();

function renderGridTimeline() {
  const container = gridElements?.timelineContainer;
  if (!container) return;
  const columns = (currentLg * currentDenominator) / currentNumerator;
  const n = currentNumerator;
  const d = currentDenominator;

  container.innerHTML = '';
  const row = document.createElement('div');
  row.className = 'plano-timeline-row';

  for (let colIdx = 0; colIdx < columns; colIdx++) {
    const numEl = document.createElement('div');
    numEl.className = 'plano-timeline-number';
    numEl.dataset.colIndex = colIdx;
    numEl.style.left = `${(colIdx / columns) * 100}%`;

    const positionNum = colIdx * n;
    const isIntPulse = positionNum % d === 0;
    if (isIntPulse) {
      numEl.classList.add('plano-cycle-start');
      numEl.textContent = String(positionNum / d);
    } else {
      numEl.classList.add('plano-subdivision');
      numEl.textContent = `.${colIdx % d}`;
    }
    row.appendChild(numEl);
  }

  // Endpoint marker
  const end = document.createElement('div');
  end.className = 'plano-timeline-number plano-cycle-end';
  end.dataset.colIndex = columns;
  end.style.left = '100%';
  end.textContent = '·';
  row.appendChild(end);

  container.appendChild(row);
}

function renderGhostLines() {
  const matrix = gridElements?.matrixContainer?.querySelector('.plano-matrix');
  if (!matrix || !cellWidth) return;
  renderGhostPulseLines(matrix, {
    lg: currentLg,
    numerator: currentNumerator,
    denominator: currentDenominator,
    cellWidth
  });
}
```

