Combine plano-modular + fraction editor (simple) + halters. No nit-editor here.

```javascript
import { createApp19Grid } from '../../libs/plano-modular/index.js';
import createFractionEditor from '../../libs/app-common/fraction-editor.js';
import { renderNoteBars } from '../../libs/app-common/plano-note-renderer.js';
import { createIntervalLabelBar } from '../../libs/shared-ui/interval-label-bar.js';

const NOTE_COUNT = 12;
const REGISTRIES = [3, 4, 5];
let currentDenominator = 2;
const FIXED_NUMERATOR = 1;
const FIXED_LG = 12;
let notes = [];
let cellWidth = 0;

// 1. Multi-registry grid
const grid = createApp19Grid({
  parent: document.getElementById('gridContainer'),
  columns: FIXED_LG * currentDenominator,  // n=1: columns = lg * d
  registries: REGISTRIES,
  rowsPerRegistry: NOTE_COUNT,
  initialRegistry: 4,
  columnSizing: 'fr',
  playheadOffset: 0
});

// 2. Simple fraction editor in .middle
const controller = createFractionEditor({
  mode: 'block',
  host: fractionSlot,
  defaults: { numerator: FIXED_NUMERATOR, denominator: currentDenominator },
  startEmpty: false,
  maxDenominator: 8,
  enableGhost: false,  // simple n=1
  addRepeatPress,
  onChange: ({ cause }) => {
    if (cause !== 'init') handleFractionChange();
  }
});
controller.setSimpleMode();

// 3. Note rendering + halters
function renderNotes() {
  renderNoteBars({
    matrixContainer: grid.matrixContainer,
    notes,
    cellWidth,
    noteCount: NOTE_COUNT,
    colors: ['#bdd9e6'],     // blau clar
    onClickNote: removeNote
  });
  renderNoteHalters();
}

function renderNoteHalters() {
  const matrix = grid.matrixContainer.querySelector('.plano-matrix');
  if (!matrix) return;
  matrix.querySelectorAll('.note-halter').forEach(el => el.remove());

  const firstCell = matrix.querySelector('.plano-cell');
  const cellH = firstCell?.offsetHeight || 32;
  const matrixWidth = matrix.offsetWidth;

  notes.forEach((noteData) => {
    if (noteData.isRest) return;
    const startPercent = (noteData.startSubdiv * cellWidth / matrixWidth) * 100;
    const widthPercent = (noteData.duration * cellWidth / matrixWidth) * 100;
    const rowIndex = (NOTE_COUNT - 1) - noteData.note;
    const barTop = (rowIndex + 1) * cellH - (cellH - 2) / 2;
    const halterTop = barTop + (cellH - 2);

    const halter = createIntervalLabelBar({
      startPercent, widthPercent,
      label: noteData.duration, variant: 'solid'
    });
    halter.classList.add('note-halter');
    halter.style.top = `${halterTop}px`;
    matrix.appendChild(halter);
  });
}
```

L'usuari dibuixa notes drag-to-create al matrix multi-registre. Cada nota apareix com a barra blava amb durada via halter groc sota. La fracció simple controla la subdivisió de cada pols.

