```javascript
import { createIntervalLabelBar } from '../../libs/shared-ui/interval-label-bar.js';

const VIBRANT_COLORS = ['#7CD6B3', '#F5C6C2', '#FF9F76', '#9BB7F8'];
const TOTAL_PULSES = 8;
let itSequence = [];
let currentColorAssignments = [];

function updateTimeline() {
  const timeline = document.getElementById('timeline');
  timeline.querySelectorAll('.interval-bar-visual, .interval-label-bar').forEach(el => el.remove());

  if (!currentColorAssignments || currentColorAssignments.length !== itSequence.length) {
    currentColorAssignments = itSequence.map((_, idx) => VIBRANT_COLORS[idx % VIBRANT_COLORS.length]);
  }

  let currentPulse = 0;
  itSequence.forEach((iT, idx) => {
    if (iT <= 0) return;
    const color = currentColorAssignments[idx];
    const startPercent = (currentPulse / TOTAL_PULSES) * 100;
    const widthPercent = (iT / TOTAL_PULSES) * 100;

    const bar = document.createElement('div');
    bar.className = 'interval-bar-visual';
    bar.style.left = `${startPercent}%`;
    bar.style.width = `${widthPercent}%`;
    bar.style.background = color;
    timeline.appendChild(bar);

    const halter = createIntervalLabelBar({
      startPercent, widthPercent, label: iT, variant: 'solid'
    });
    timeline.appendChild(halter);

    currentPulse += iT;
  });
}
```

Aquí no hi ha fracció (es treballa amb polsos enters només), però es mantenen les barres colorides + halters per indicar la durada de cada iT.

