```javascript
import { showValidationWarning } from '../../libs/app-common/info-tooltip.js';

let selectedPulses = new Set();   // tokens "N" o "N.M"
let pfrCommitTimer = null;

// Helpers
function normalizeToken(raw) {
  const t = raw.trim();
  // Bare digit "5" → keep as "5"
  if (/^\d+$/.test(t)) return t;
  // "N.M" → keep
  if (/^\d+\.\d+$/.test(t)) return t;
  // ".M" shorthand → "0.M"
  if (/^\.\d+$/.test(t)) return `0${t}`;
  return null;
}

function isValidPulseToken(token) {
  // Valid: "N" where 0 ≤ N < Lg, or "N.M" where N ≤ Lg-1 and 0 < M < d
  if (/^\d+$/.test(token)) {
    const n = parseInt(token, 10);
    return n >= 0 && n < FIXED_LG;
  }
  if (/^\d+\.\d+$/.test(token)) {
    const [n, m] = token.split('.').map(Number);
    return n >= 0 && n < FIXED_LG && m > 0 && m < currentDenominator;
  }
  return false;
}

function pulseTokenValue(token) {
  if (/^\d+$/.test(token)) return parseInt(token, 10);
  const [n, m] = token.split('.').map(Number);
  return n + m / currentDenominator;
}

// Commit handler (cridat des de la cell input)
function tryCommitFromInput(cell) {
  const raw = cell.value.trim();
  if (!raw) return false;

  const token = normalizeToken(raw);
  if (!token) {
    showValidationWarning(pfrEditorEl, `"${raw}" no es válido`);
    cell.value = ''; setTimeout(() => cell.focus(), 10);
    return false;
  }

  if (!isValidPulseToken(token)) {
    showValidationWarning(pfrEditorEl, `"${token}" fuera de rango`);
    cell.value = ''; setTimeout(() => cell.focus(), 10);
    return false;
  }

  if (selectedPulses.has(token)) {
    showValidationWarning(pfrEditorEl, `"${token}" duplicado`);
    cell.value = ''; setTimeout(() => cell.focus(), 10);
    return false;
  }

  if (token !== raw) {
    showValidationWarning(pfrEditorEl, `Corregido: ${raw}→${token}`);
  }

  selectedPulses.add(token);
  renderPfrEditor();
  syncToTimeline();
  return true;
}
```

L'editor accepta tokens com `"3"` (pols 3 enter), `"3.2"` (subdivisió 2 del pols 3), o `".1"` (shorthand per `"0.1"`). Cada token es valida i normalitza abans d'afegir-se a `selectedPulses`.

