```javascript
import { createApp19Grid } from '../../libs/plano-modular/index.js';
import createFractionEditor from '../../libs/app-common/fraction-editor.js';
import { createScalePill } from '../../libs/app-common/scale-pill.js';
import { renderGhostPulseLines } from '../../libs/plano-fraccion/ghost-pulse.js';
import { calculateVariableLg as _calcLg } from '../../libs/plano-fraccion/fraction-math.js';

const SCALES = [
  { value: 'DIAT-0', name: 'Diatónica', length: 7 },
  { value: 'PENT-0', name: 'Pentatónica', length: 5 }
];

let currentScale = SCALES[0];
let currentNumerator = 2;
let currentDenominator = 3;
let currentLg = _calcLg(currentNumerator, 12);

// 1. Grid multi-registre amb Nº labels segons scale
let grid = createApp19Grid({
  parent: document.getElementById('gridContainer'),
  columns: (currentLg * currentDenominator) / currentNumerator,
  registries: [3, 4, 5],
  rowsPerRegistry: currentScale.length,
  initialRegistry: 4,
  columnSizing: 'fr',
  playheadOffset: 0,
  labelFormatter: (rowData) => `Nº${rowData.degree}`
});

// 2. Fraction editor complex
const controller = createFractionEditor({
  mode: 'block',
  host: fractionSlot,
  defaults: { numerator: currentNumerator, denominator: currentDenominator },
  autoReduce: true,
  minNumerator: 2,
  maxNumerator: 6,
  minDenominator: 2,
  maxDenominator: 8,
  addRepeatPress,
  onChange: handleFractionChange
});
controller.setComplexMode();

// 3. Scale pill — quan canvia, recrear el grid amb noves rows
createScalePill({
  scales: SCALES,
  initial: currentScale.value,
  onChange: (scale) => {
    currentScale = scale;
    grid.destroy();
    grid = createApp19Grid({
      parent: document.getElementById('gridContainer'),
      columns: (currentLg * currentDenominator) / currentNumerator,
      registries: [3, 4, 5],
      rowsPerRegistry: scale.length,
      initialRegistry: 4,
      columnSizing: 'fr',
      playheadOffset: 0,
      labelFormatter: (rowData) => `Nº${rowData.degree}`
    });
  }
});

function handleFractionChange({ cause }) {
  if (cause === 'init') return;
  const f = controller.getFraction();
  if (!Number.isFinite(f.numerator) || !Number.isFinite(f.denominator)) return;
  currentNumerator = f.numerator;
  currentDenominator = f.denominator;
  currentLg = _calcLg(currentNumerator, 12);
  grid.setColumns((currentLg * currentDenominator) / currentNumerator);
  renderGhostLines();
}
```

Les 3 features (scale + multi-registres + fracció complexa) componen sense conflicte perquè toquen aspectes ortogonals: scale → Y-axis labels, registres → vertical scroll, fracció → X-axis subdivisions.

