```javascript
function renderCircularTimeline() {
  const timeline = document.getElementById('timeline');
  timeline.innerHTML = '';
  const cx = 50, cy = 50, r = 45;  // % units
  for (let i = 0; i < TOTAL_PULSES; i++) {
    const angle = (i / TOTAL_PULSES) * 2 * Math.PI - Math.PI / 2;
    const x = cx + r * Math.cos(angle);
    const y = cy + r * Math.sin(angle);
    const num = document.createElement('div');
    num.className = 'pulse-number';
    num.dataset.index = i;
    num.textContent = i;
    num.style.left = `${x}%`;
    num.style.top = `${y}%`;
    num.style.transform = 'translate(-50%, -50%)';
    timeline.appendChild(num);
  }
}
```

