```javascript
function renderCompasArc() {
  const svg = document.querySelector('.compas-arc-svg');
  const pulsesInCompas = 4;  // ex. compás de 4/4
  const totalPulses = 8;
  const startAngle = -Math.PI / 2;  // top of circle
  const endAngle = startAngle + (pulsesInCompas / totalPulses) * 2 * Math.PI;

  const cx = 50, cy = 50, r = 40;
  const x1 = cx + r * Math.cos(startAngle);
  const y1 = cy + r * Math.sin(startAngle);
  const x2 = cx + r * Math.cos(endAngle);
  const y2 = cy + r * Math.sin(endAngle);

  const path = svg.querySelector('path.compas-arc');
  path.setAttribute('d', `M ${x1} ${y1} A ${r} ${r} 0 0 1 ${x2} ${y2}`);
}
```

