Use the TimelineAudio engine with a sequence array:

```javascript
import TimelineAudio from '../../libs/sound/index.js';
import { createMelodicAudioInitializer } from '../../libs/app-common/audio-init.js';

let audio = null;
let sequence = [];   // {pulse, note, duration}[]
let isPlaying = false;

const initAudio = createMelodicAudioInitializer({ defaultInstrument: 'piano' });

async function startPlayback() {
  if (!audio) audio = await initAudio();
  if (!audio) return;

  isPlaying = true;
  playIcon.style.display = 'none';
  stopIcon.style.display = 'block';

  audio.setBpm(currentBpm);
  audio.setBaseResolution(currentDenominator);  // = d (NOT n * d)
  audio.setNotes(sequence.map(n => ({ pulse: n.pulse, note: n.note, duration: n.duration })));

  audio.start({
    onPulse: (step) => highlightAtStep(step),
    onComplete: () => {
      // Delay stop so the last pulse highlight is visible
      const lastNoteDelay = (60 / currentBpm) * 0.9 * 1000;
      setTimeout(() => stopPlayback(), lastNoteDelay);
    }
  });
}

function stopPlayback() {
  if (!isPlaying) return;
  isPlaying = false;
  audio?.stop();
  highlightController?.clearHighlights();
  document.querySelectorAll('.musical-cell.playing, .note-bar.highlight')
    .forEach(c => c.classList.remove('playing', 'highlight'));
  playIcon.style.display = 'block';
  stopIcon.style.display = 'none';
}

playBtn.addEventListener('click', async () => {
  if (isPlaying) stopPlayback();
  else await startPlayback();
});
```

The `audio.setNotes()` accepts an array of `{pulse, note, duration}` objects. `audio.start()` schedules each note's playback and fires `onPulse(step)` for visual highlighting. The `setTimeout` in `onComplete` ensures the last pulse highlight is visible before clearing.

