// main.js
import { setupRandomMenu } from '../../libs/random/menu.js';
import { randomInt, gcd } from '../../libs/app-common/number-utils.js';

const MAX_NUMERATOR = 6;
const MAX_DENOMINATOR = 8;
let randomMenu = null;
let isPlaying = false;

function init() {
  randomMenu = setupRandomMenu({
    spec: {
      numMax:   { label: 'Numerador máximo',   min: 1, max: MAX_NUMERATOR,   default: MAX_NUMERATOR },
      denomMax: { label: 'Denominador máximo', min: 2, max: MAX_DENOMINATOR, default: MAX_DENOMINATOR },
    },
    onRandomize: handleRandom,
  });
}

function handleRandom() {
  if (isPlaying) return;
  const { numMax, denomMax } = randomMenu?.read() ?? { numMax: MAX_NUMERATOR, denomMax: MAX_DENOMINATOR };
  const nMax = Math.min(numMax, MAX_NUMERATOR);
  const dMax = Math.min(denomMax, MAX_DENOMINATOR);
  let n, d;
  do { n = randomInt(1, nMax); d = randomInt(2, dMax); } while (gcd(n, d) !== 1);
  setFraction(n, d);
  if (!isPlaying) playSequence();
}

init();
```

Clave: `randomMenuContent: ''`, clamp con `Math.min(menuValue, HARD_MAX)`, y auto-play tras randomizar.

Use `setupRandomMenu` from `libs/random/menu.js`. It handles both gestures (shortpress → randomize, longpress ≥500ms → open menu) in a single call:

```javascript
