    regMin: { label: 'Registro mínimo', min: MIN_REGISTRO, max: MAX_REGISTRO, default: MIN_REGISTRO },
    regMax: { label: 'Registro máximo', min: MIN_REGISTRO, max: MAX_REGISTRO, default: MAX_REGISTRO },
    notes:  { label: 'Número de notas',  min: 1,            max: MAX_NOTES,    default: 6 },
    bpmMin: { label: 'BPM mínimo',       min: MIN_BPM,      max: MAX_BPM,      default: MIN_BPM },
    bpmMax: { label: 'BPM máximo',       min: MIN_BPM,      max: MAX_BPM,      default: MAX_BPM },
  },
  onRandomize: handleRandom,
});

function handleRandom() {
  const cfg = randomMenu?.read() ?? {
    regMin: MIN_REGISTRO, regMax: MAX_REGISTRO,
    notes: 6, bpmMin: MIN_BPM, bpmMax: MAX_BPM,
  };
  const rMin = Math.max(MIN_REGISTRO, Math.min(cfg.regMin, cfg.regMax));
  const rMax = Math.min(MAX_REGISTRO, Math.max(cfg.regMin, cfg.regMax));
  const bMin = Math.max(MIN_BPM, Math.min(cfg.bpmMin, cfg.bpmMax));
  const bMax = Math.min(MAX_BPM, Math.max(cfg.bpmMin, cfg.bpmMax));
  setRegisterRange(rMin, rMax);
  setBpm(randomInt(bMin, bMax));
  generateNotes(cfg.notes);
  if (!isPlaying) playSequence();
}
```

Note the cross-validation: `regMin` and `regMax` are normalized so a user who flips them by mistake gets the same effective range. Same for BPM.

Per una app de timeline + fracció simple (com App26/28/30), només cal exposar `denomMax` (el numerador sempre és 1 en fraccions simples):

```javascript
import { setupRandomMenu } from '../../libs/random/menu.js';

const MAX_DENOMINATOR = 8;
let randomMenu = null;

function init() {
  randomMenu = setupRandomMenu({
    spec: {
      denomMax: { label: 'Denominador máximo', min: 2, max: MAX_DENOMINATOR, default: MAX_DENOMINATOR },
    },
    onRandomize: handleRandom,
  });
}

function handleRandom() {
  if (isPlaying) return;
  const { denomMax } = randomMenu?.read() ?? { denomMax: MAX_DENOMINATOR };
  const d = Math.min(denomMax, MAX_DENOMINATOR);
  setDenominator(randomInt(2, d));
  if (!isPlaying) playSequence();
}
```

La idea és que l'usuari pot decidir "vull veure exemples amb denominadors no més grans que 4" via long-press, però mai pot demanar `denomMax > 8` perquè és el límit estructural de l'app. El `Math.min(denomMax, MAX_DENOMINATOR)` dins del handler és la garantia.

El patró canònic té 4 passos, en aquest ordre:

```javascript
function handleRandom() {
  // 1. Ignorar si està sonant
  if (isPlaying) return;

  // 2. Llegir valors del menú (amb defaults segurs)
  const { numMax, denomMax } = randomMenu?.read() ?? {
    numMax: MAX_NUMERATOR,
    denomMax: MAX_DENOMINATOR,
  };

  // 3. Clamp als hard limits — el menú estreny, mai eixampla
  const nMax = Math.min(numMax, MAX_NUMERATOR);
  const dMax = Math.min(denomMax, MAX_DENOMINATOR);

  // 4. Generar respectant invariants (p.ex. gcd=1 per a fraccions reduïdes)
  let n, d;
  do {
    n = randomInt(1, nMax);
    d = randomInt(2, dMax);
  } while (gcd(n, d) !== 1);
  setFraction(n, d);

  // 5. Auto-play després de randomitzar (consistent a totes les apps 9-35)
  if (!isPlaying) playSequence();
}
```

Els passos crítics són el 3 (clamp) i el 5 (auto-play). El clamp protegeix del cas que l'usuari editi l'HTML del menú a mà. L'auto-play forma part de la filosofia pedagògica: aleatoritzar i no sentir res seria silenciar la pista informativa principal.

Compose them: `numMax + denomMax` (complex fraction) + `regMin + regMax` (registers) + optionally `notes` (note count):

```javascript
